EQUIPMENT_ATTACHED_KEYWORD_WORDS = {
    keyword.replace("_", " "): keyword
    for keyword in EQUIPMENT_ATTACHED_KEYWORD_CLASSES.values()
}


def _equipment_oracle_keyword_list(value: str) -> list[str] | None:
    if not value:
        return []
    if '"' in value or " and is " in value or " can " in value or " can't " in value or " must " in value:
        return None
    normalized = (
        value.strip()
        .rstrip(".")
        .replace(", and ", ", ")
        .replace(" and ", ", ")
    )
    keywords: list[str] = []
    for raw_part in [part.strip() for part in normalized.split(",") if part.strip()]:
        keyword = EQUIPMENT_ATTACHED_KEYWORD_WORDS.get(raw_part)
        if not keyword:
            return None
        keywords.append(keyword)
    return sorted(set(keywords))


def fixed_equipment_static_attachment_from_oracle(
    metadata: dict[str, Any],
) -> dict[str, Any] | str | None:
    text = re.sub(r"\s*\([^)]*\)", "", str(metadata.get("oracle_text") or ""))
    lines = [
        re.sub(r"\s+", " ", line.strip().lower()).rstrip(".")
        for line in text.splitlines()
        if line.strip()
    ]
    static_lines: list[str] = []
    for line in lines:
        if line.startswith("equip "):
            continue
        static_lines.append(line)
    if len(static_lines) != 1:
        return None
    match = re.match(
        r"^equipped creature gets (?P<power>[+-]?\d+)/(?P<toughness>[+-]?\d+)(?P<tail>.*)$",
        static_lines[0],
    )
    if not match:
        return None
    tail = match.group("tail").strip()
    keyword_text = ""
    if tail:
        if tail.startswith("and has "):
            keyword_text = tail[len("and has ") :].strip()
        elif tail.startswith(", has "):
            keyword_text = tail[len(", has ") :].strip()
        elif tail.startswith(", and has "):
            keyword_text = tail[len(", and has ") :].strip()
        else:
            return None
    keywords = _equipment_oracle_keyword_list(keyword_text)
    if keywords is None:
        return "equipment_static_oracle_keyword_not_supported"
    return {
        "power_boost": int(match.group("power")),
        "toughness_boost": int(match.group("toughness")),
        "attached_keywords": keywords,
    }


def fixed_equipment_static_attachment_from_source(source: str) -> dict[str, Any] | str | None:
    text = source or ""
    boost_matches = re.findall(
        r"new\s+BoostEquippedEffect\s*\(\s*([+-]?\d+)\s*,\s*([+-]?\d+)"
        r"\s*(?:,\s*Duration\.WhileOnBattlefield)?\s*\)",
        text,
        re.S,
    )
    if len(boost_matches) != 1:
        return "equipment_static_source_boost_not_single_fixed"
    attached_effect_blocks = re.findall(
        r"GainAbilityAttachedEffect\s*\(\s*(.*?)AttachmentType\.EQUIPMENT",
        text,
        re.S,
    )
    keywords: set[str] = set()
    for block in attached_effect_blocks:
        found = False
        for class_name, keyword in EQUIPMENT_ATTACHED_KEYWORD_CLASSES.items():
            if re.search(rf"\b(?:new\s+)?{re.escape(class_name)}\b", block):
                keywords.add(keyword)
                found = True
                break
        if not found:
            return "equipment_static_source_keyword_not_supported"
    power_raw, toughness_raw = boost_matches[0]
    return {
        "power_boost": int(power_raw),
        "toughness_boost": int(toughness_raw),
        "attached_keywords": sorted(keywords),
    }


def java_constructor_int(source: str, class_name: str, *, default: int | None = None) -> int | None:
    match = re.search(rf"\b{re.escape(class_name)}\s*\(\s*(\d+)\b", source)
    if match:
        return int(match.group(1))
    return default


def java_constructor_int_or_noarg_default(
    source: str,
    class_name: str,
    *,
    noarg_default: int,
) -> int | None:
    amount = java_constructor_int(source, class_name)
    if amount is not None:
        return amount
    if re.search(rf"\b{re.escape(class_name)}\s*\(\s*\)", source or ""):
        return noarg_default
    return None


def has_additional_cost(source: str) -> bool:
    return bool(re.search(r"\.addCost\s*\(", source or ""))


def source_xmage_root(row: dict[str, Any]) -> Path | None:
    path = Path(str(row.get("xmage_path") or ""))
    parts = path.parts
    for marker in ("Mage.Sets", "Mage"):
        if marker in parts:
            index = parts.index(marker)
            if index > 0:
                return Path(*parts[:index])
    return None


def controlled_subtype_token_count_from_filter(source: str, filter_var: str) -> dict[str, Any] | None:
    text = source or ""
    filter_name = str(filter_var or "").strip()
    if not filter_name or not re.match(r"^[A-Za-z_]\w*$", filter_name):
        return None
    if not re.search(
        rf"(?:private\s+static\s+final\s+)?FilterControlledPermanent\s+{re.escape(filter_name)}\s*="
        r"\s*new\s+FilterControlledPermanent\s*\(",
        text,
    ):
        return None
    subtype_matches = re.findall(
        rf"{re.escape(filter_name)}\.add\s*\(\s*SubType\.([A-Z0-9_]+)\.getPredicate\s*\(\s*\)\s*\)",
        text,
    )
    if len(set(subtype_matches)) != 1:
        return None
    return {
        "token_count_source": "controlled_permanents_with_subtype",
        "token_count_subtype": title_subtype(subtype_matches[0]),
    }


def controlled_tapped_creature_token_count_from_filter(source: str, filter_var: str) -> dict[str, Any] | None:
    text = source or ""
    filter_name = str(filter_var or "").strip()
    if not filter_name or not re.match(r"^[A-Za-z_]\w*$", filter_name):
        return None
    if not re.search(
        rf"(?:private\s+static\s+final\s+)?FilterPermanent\s+{re.escape(filter_name)}\s*="
        r"\s*new\s+FilterControlledCreaturePermanent\s*\(",
        text,
    ):
        return None
    if not re.search(rf"{re.escape(filter_name)}\.add\s*\(\s*TappedPredicate\.TAPPED\s*\)", text):
        return None
    return {"token_count_source": "controlled_tapped_creatures"}


def controlled_subtype_token_count_from_source(source: str, count_expression: str) -> dict[str, Any] | None:
    text = source or ""
    count_var = str(count_expression or "").strip()
    if not count_var or not re.match(r"^[A-Za-z_]\w*$", count_var):
        return None
    count_match = re.search(
        rf"(?:private\s+static\s+final\s+)?(?:DynamicValue|PermanentsOnBattlefieldCount)\s+"
        rf"{re.escape(count_var)}\s*=\s*new\s+PermanentsOnBattlefieldCount\s*\(\s*(?P<filter>\w+)"
        r"(?:\s*,\s*[^)]*)?\)",
        text,
    )
    if not count_match:
        return None
    return (
        controlled_subtype_token_count_from_filter(text, count_match.group("filter"))
        or controlled_tapped_creature_token_count_from_filter(text, count_match.group("filter"))
    )


def permanents_count_token_count_from_expression(source: str, count_expression: str) -> dict[str, Any] | None:
    args = extract_java_call_args(str(count_expression or ""), "PermanentsOnBattlefieldCount")
    if args is None:
        return None
    parts = split_java_args(args)
    if not parts:
        return None
    filter_expression = parts[0].strip()
    if re.fullmatch(r"\w+", filter_expression):
        return (
            controlled_subtype_token_count_from_filter(source, filter_expression)
            or controlled_tapped_creature_token_count_from_filter(source, filter_expression)
        )
    if re.search(r"new\s+FilterCreaturePermanent\s*\(", filter_expression):
        return {"token_count_source": "all_creatures_on_battlefield"}
    if filter_expression == "StaticFilters.FILTER_ATTACKING_CREATURES":
        return {"token_count_source": "attacking_creatures"}
    return None


def graveyard_count_token_count_from_expression(count_expression: str) -> dict[str, Any] | None:
    args = extract_java_call_args(str(count_expression or ""), "CardsInControllerGraveyardCount")
    if args is None:
        return None
    parts = split_java_args(args)
    if not parts:
        return None
    filter_expression = parts[0].strip()
    if filter_expression == "StaticFilters.FILTER_CARD_INSTANT_AND_SORCERY":
        return {"token_count_source": "controller_graveyard_instant_sorcery_count"}
    if filter_expression == "StaticFilters.FILTER_CARD_CREATURES":
        return {"token_count_source": "controller_graveyard_creature_count"}
    return None


def variable_dynamic_token_count_from_source(source: str, variable_name: str) -> dict[str, Any] | None:
    text = source or ""
    var = str(variable_name or "").strip()
    if not var or not re.match(r"^[A-Za-z_]\w*$", var):
        return None
    assignment_match = re.search(
        rf"(?:private\s+static\s+final\s+)?(?:DynamicValue|PermanentsOnBattlefieldCount|CardsInControllerGraveyardCount)\s+"
        rf"{re.escape(var)}\s*=\s*(?P<expr>new\s+(?:PermanentsOnBattlefieldCount|CardsInControllerGraveyardCount)\s*\([^;]+?\))\s*;",
        text,
        re.S,
    )
    if not assignment_match:
        return None
    expression = assignment_match.group("expr")
    return (
        permanents_count_token_count_from_expression(text, expression)
        or graveyard_count_token_count_from_expression(expression)
    )


def named_graveyard_plus_base_token_count_from_source(source: str, count_expression: str) -> dict[str, Any] | None:
    text = source or ""
    match = re.fullmatch(r"(?P<class>\w+)\.instance", str(count_expression or "").strip())
    if not match:
        return None
    class_name = match.group("class")
    class_block_match = re.search(
        rf"(?:enum|class)\s+{re.escape(class_name)}\s+implements\s+DynamicValue\b(?P<body>.*?)(?:\n\}}\s*$|\n\}}\s*\n\s*(?:class|enum)\s+)",
        text,
        re.S,
    )
    class_block = class_block_match.group("body") if class_block_match else text
    name_match = re.search(r'new\s+NamePredicate\s*\(\s*"(?P<name>[^"]+)"\s*\)', class_block)
    return_match = re.search(r"return\s+amount\s*\+\s*(?P<base>\d+)\s*;", class_block)
    if not name_match or not return_match:
        return None
    return {
        "token_count_source": "named_cards_in_controller_graveyard_plus_base",
        "token_count_card_name": name_match.group("name"),
        "token_count_base": int(return_match.group("base")),
    }


def dynamic_token_count_from_source(source: str, count_expression: str) -> dict[str, Any] | None:
    expression = str(count_expression or "").strip()
    if expression == "GetXValue.instance":
        return {"token_count_source": "x_value", "token_count_per_x": 1}
    if expression == "GreatestAmongPermanentsValue.POWER_CONTROLLED_CREATURES":
        return {"token_count_source": "greatest_power_among_controlled_creatures"}
    if expression == "DomainValue.REGULAR":
        return {"token_count_source": "domain_basic_land_types"}
    if expression == "CardsInControllerHandCount.ANY":
        return {"token_count_source": "controller_hand_count"}
    if re.fullmatch(r"\w+", expression):
        return (
            controlled_subtype_token_count_from_source(source, expression)
            or variable_dynamic_token_count_from_source(source, expression)
        )
    if "PermanentsOnBattlefieldCount" in expression:
        return permanents_count_token_count_from_expression(source, expression)
    if "CardsInControllerGraveyardCount" in expression:
        return graveyard_count_token_count_from_expression(expression)
    return named_graveyard_plus_base_token_count_from_source(source, expression)


def fixed_create_token_effect_from_source(source: str) -> tuple[str, int] | dict[str, Any] | str:
    text = source or ""
    if len(re.findall(r"new\s+CreateTokenEffect\s*\(", text)) != 1:
        return "token_source_not_single_create_token_effect"
    if ".withAdditionalTokens" in text:
        return "token_source_additional_tokens_not_supported"
    if ".entersWithCounters" in text:
        return "token_source_counters_not_supported"
    args = extract_java_call_args(text, "CreateTokenEffect")
    if args is None:
        return "token_source_create_token_not_fixed"
    parts = split_java_args(args)
    if not parts:
        return "token_source_create_token_not_fixed"
    token_match = re.fullmatch(r"new\s+(?P<class>\w+)\s*\([^)]*\)", parts[0].strip(), re.S)
    if not token_match:
        return "token_source_create_token_not_fixed"
    token_class = token_match.group("class")
    count_expression = parts[1].strip() if len(parts) > 1 else ""
    token_tapped = len(parts) > 2 and parts[2].strip() == "true"
    if len(parts) > 3 and parts[3].strip() == "true":
        return "token_source_attacking_tokens_not_supported"
    if count_expression and not count_expression.isdigit():
        parsed_dynamic = dynamic_token_count_from_source(text, count_expression)
        if parsed_dynamic is None:
            return "token_source_create_token_not_fixed"
        parsed = {
            "token_class": token_class,
            **parsed_dynamic,
        }
        if token_tapped:
            parsed["token_tapped"] = True
        return parsed
    count = int(count_expression or "1")
    if count <= 0:
        return "token_source_count_not_positive"
    if token_tapped:
        return {"token_class": token_class, "token_count": count, "token_tapped": True}
    return token_class, count


def fixed_literal_token_parts(
    parsed_effect: tuple[str, int] | dict[str, Any] | str,
) -> tuple[str, int, dict[str, Any]] | str:
    if isinstance(parsed_effect, str):
        return parsed_effect
    if isinstance(parsed_effect, dict):
        if parsed_effect.get("token_count_source"):
            return "token_source_create_token_not_fixed"
        return (
            str(parsed_effect["token_class"]),
            int(parsed_effect.get("token_count") or 1),
            {"token_tapped": True} if parsed_effect.get("token_tapped") else {},
        )
    token_class, token_count = parsed_effect
    return str(token_class), int(token_count), {}


def multi_create_token_effects_from_source(source: str) -> list[dict[str, Any]] | str:
    text = source or ""
    if len(re.findall(r"new\s+CreateTokenEffect\s*\(", text)) != 1:
        return "multi_token_source_not_single_create_token_effect"
    if ".withAdditionalTokens" not in text:
        return "multi_token_source_no_additional_tokens"
    if ".entersWithCounters" in text:
        return "multi_token_source_counters_not_supported"
    if ".setText" in text:
        return "multi_token_source_custom_text_not_supported"
    base_match = re.search(
        r"new\s+CreateTokenEffect\s*\(\s*new\s+(?P<class>\w+)\s*\(\s*\)\s*"
        r"(?:,\s*(?P<count>\d+))?\s*\)\s*\.withAdditionalTokens\s*\(",
        text,
        re.S,
    )
    if not base_match:
        return "multi_token_source_base_create_token_not_fixed"
    base_count = int(base_match.group("count") or "1")
    if base_count != 1:
        return "multi_token_source_base_count_not_supported"
    additional_args = extract_java_call_args(text, "withAdditionalTokens")
    if additional_args is None:
        return "multi_token_source_additional_args_missing"
    token_classes = [base_match.group("class")]
    for arg in split_java_args(additional_args):
        token_match = re.fullmatch(r"new\s+(\w+)\s*\(\s*\)", arg.strip(), re.S)
        if not token_match:
            return "multi_token_source_additional_token_not_fixed"
        token_classes.append(token_match.group(1))
    if len(token_classes) < 2:
        return "multi_token_source_additional_tokens_empty"
    return [{"token_class": token_class, "token_count": 1} for token_class in token_classes]


def token_count_phrase_options(token_data: dict[str, Any], token_count: int) -> set[str]:
    token_descriptions = token_oracle_description_variants(token_data)
    if token_count == 1:
        expected: set[str] = set()
        for token_description in token_descriptions:
            expected.update(
                {
                    f"a {token_description}",
                    f"an {token_description}",
                    f"one {token_description}",
                }
            )
        return expected
    expected = set()
    for token_description in token_descriptions:
        plural_description = plural_token_description(token_description)
        expected.update(
            {
                f"{token_count} {plural_description}",
                f"{count_word_for_oracle(token_count)} {plural_description}",
            }
        )
    return expected


def token_component_from_parsed_token(
    row: dict[str, Any],
    source_text: str,
    parsed_token: dict[str, Any],
    *,
    component_scope: str,
    ability_kind: str,
    trigger: str | None = None,
) -> tuple[dict[str, Any] | None, str | None]:
    token_class = str(parsed_token["token_class"])
    token_data, token_reason = parse_simple_token_class(
        token_class_source(row, source_text, token_class),
        token_class,
    )
    if token_reason:
        return None, token_reason
    token_count = int(parsed_token.get("token_count") or 1)
    component = {
        "effect": "token_maker",
        "battle_model_scope": component_scope,
        "ability_kind": ability_kind,
        "compose_on_resolution": True,
        "token_count": token_count,
        "xmage_effect_class": "CreateTokenEffect",
        **token_data,
    }
    if trigger:
        component["trigger"] = trigger
    if parsed_token.get("token_tapped"):
        component["token_tapped"] = True
    return component, None


def token_components_from_parsed_tokens(
    row: dict[str, Any],
    source_text: str,
    parsed_tokens: list[dict[str, Any]],
    *,
    component_scope: str,
    ability_kind: str,
    trigger: str | None = None,
) -> tuple[list[dict[str, Any]] | None, list[str], str | None]:
    components: list[dict[str, Any]] = []
    token_classes: list[str] = []
    for parsed_token in parsed_tokens:
        component, reason = token_component_from_parsed_token(
            row,
            source_text,
            parsed_token,
            component_scope=component_scope,
            ability_kind=ability_kind,
            trigger=trigger,
        )
        if reason:
            return None, token_classes, reason
        token_classes.append(str(parsed_token["token_class"]))
        components.append(component or {})
    return components, token_classes, None


def multi_create_token_oracle_blocker(
    metadata: dict[str, Any],
    components: list[dict[str, Any]],
    *,
    trigger: str | None,
) -> str | None:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    if any(marker in text for marker in (" if ", " for each ", " where x ", " equal to ", " instead ")):
        return f"{trigger or 'token'}_multi_token_oracle_not_simple"
    if trigger == "enters_battlefield":
        match = re.match(
            r"^(?:when|whenever) (?:this creature|[^,.]+) enters(?: the battlefield)?, create (?P<phrase>.+)$",
            text,
        )
        blocker = "etb_token_oracle_not_simple"
    elif trigger == "dies":
        match = re.match(
            r"^(?:when|whenever) (?:this creature|[^,.]+) dies, create (?P<phrase>.+)$",
            text,
        )
        blocker = "dies_token_oracle_not_simple"
    else:
        match = re.match(r"^create (?P<phrase>.+)$", text)
        blocker = "token_oracle_not_simple"
    if not match:
        return blocker
    phrase = match.group("phrase").strip().rstrip(".")
    for component in components:
        token_count = int(component.get("token_count") or 1)
        if not any(option in phrase for option in token_count_phrase_options(component, token_count)):
            return blocker
    return None


def token_class_source(row: dict[str, Any], source_text: str, token_class: str) -> str:
    if re.search(rf"\bclass\s+{re.escape(token_class)}\b", source_text or ""):
        return source_text
    root = source_xmage_root(row)
    if root is None:
        return ""
    direct = root / "Mage" / "src" / "main" / "java" / "mage" / "game" / "permanent" / "token" / f"{token_class}.java"
    if direct.is_file():
        return direct.read_text(encoding="utf-8", errors="replace")
    for base in (
        root / "Mage" / "src" / "main" / "java",
        root / "Mage.Sets" / "src" / "mage" / "cards",
    ):
        if not base.is_dir():
            continue
        for candidate in base.rglob(f"{token_class}.java"):
            return candidate.read_text(encoding="utf-8", errors="replace")
    return ""


def title_subtype(value: str) -> str:
    return " ".join(part.capitalize() for part in str(value or "").split("_") if part)


def token_colors_from_description(description: str) -> list[str]:
    lower = str(description or "").lower()
    if "colorless" in lower:
        return []
    return [
        symbol
        for color_word, symbol in TOKEN_COLOR_WORDS.items()
        if re.search(rf"\b{re.escape(color_word)}\b", lower)
    ]


JAVA_STRING_ESCAPE_VALUES = {
    "b": "\b",
    "f": "\f",
    "n": "\n",
    "r": "\r",
    "t": "\t",
    '"': '"',
    "'": "'",
    "\\": "\\",
}


def extract_java_call_args(source: str, call_name: str) -> str | None:
    match = re.search(rf"\b{re.escape(call_name)}\s*\(", source or "")
    if not match:
        return None
    text = str(source or "")
    open_index = text.find("(", match.start())
    depth = 0
    in_string = False
    escaped = False
    for index in range(open_index, len(text)):
        char = text[index]
        if in_string:
            if escaped:
                escaped = False
            elif char == "\\":
                escaped = True
            elif char == '"':
                in_string = False
            continue
        if char == '"':
            in_string = True
            continue
        if char == "(":
            depth += 1
        elif char == ")":
            depth -= 1
            if depth == 0:
                return text[open_index + 1 : index]
    return None


def split_java_args(arg_text: str) -> list[str]:
    args: list[str] = []
    current: list[str] = []
    depth = 0
    in_string = False
    escaped = False
    for char in str(arg_text or ""):
        if in_string:
            current.append(char)
            if escaped:
                escaped = False
            elif char == "\\":
                escaped = True
            elif char == '"':
                in_string = False
            continue
        if char == '"':
            in_string = True
            current.append(char)
            continue
        if char == "," and depth == 0:
            args.append("".join(current).strip())
            current = []
            continue
        current.append(char)
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
    if current:
        args.append("".join(current).strip())
    return args


def decode_java_string_literal(literal: str) -> str | None:
    text = str(literal or "").strip()
    if len(text) < 2 or not text.startswith('"') or not text.endswith('"'):
        return None
    result: list[str] = []
    index = 1
    while index < len(text) - 1:
        char = text[index]
        if char == "\\" and index + 1 < len(text) - 1:
            escaped = text[index + 1]
            result.append(JAVA_STRING_ESCAPE_VALUES.get(escaped, escaped))
            index += 2
            continue
        result.append(char)
        index += 1
    return "".join(result)


def evaluate_java_string_expression(expression: str) -> str | None:
    text = str(expression or "").strip()
    if not text:
        return None
    result: list[str] = []
    index = 0
    while index < len(text):
        while index < len(text) and text[index].isspace():
            index += 1
        if index < len(text) and text[index] == "+":
            index += 1
            continue
        if index >= len(text):
            break
        if text[index] != '"':
            return None
        end = index + 1
        escaped = False
        while end < len(text):
            char = text[end]
            if escaped:
                escaped = False
                end += 1
                continue
            if char == "\\":
                escaped = True
                end += 1
                continue
            if char == '"':
                break
            end += 1
        if end >= len(text):
            return None
        literal = decode_java_string_literal(text[index : end + 1])
        if literal is None:
            return None
        result.append(literal)
        index = end + 1
        while index < len(text) and text[index].isspace():
            index += 1
        if index < len(text) and text[index] != "+":
            return None
    return "".join(result) if result else None


def token_super_name_and_description(constructor_source: str) -> tuple[str, str] | None:
    args = extract_java_call_args(constructor_source, "super")
    if args is None:
        return None
    parts = split_java_args(args)
    if len(parts) < 2:
        return None
    token_name = evaluate_java_string_expression(parts[0])
    description = evaluate_java_string_expression(parts[1])
    if token_name is None or description is None:
        return None
    return token_name, description


def token_noarg_constructor_body(token_source: str, token_class: str) -> str | None:
    constructor_match = re.search(
        rf"public\s+{re.escape(token_class)}\s*\(\s*\)\s*\{{(?P<body>.*?)\n\s*\}}",
        token_source,
        re.S,
    )
    return constructor_match.group("body") if constructor_match else None


def token_constructor_body_with_literal_super(token_source: str, token_class: str) -> str | None:
    noarg_body = token_noarg_constructor_body(token_source, token_class)
    if noarg_body is None:
        return None
    if token_super_name_and_description(noarg_body) is not None:
        return noarg_body
    if not re.search(r"\bthis\s*\(", noarg_body):
        return noarg_body
    for constructor_match in re.finditer(
        rf"public\s+{re.escape(token_class)}\s*\([^)]*\)\s*\{{(?P<body>.*?)\n\s*\}}",
        token_source,
        re.S,
    ):
        candidate_body = constructor_match.group("body")
        if candidate_body == noarg_body:
            continue
        if token_super_name_and_description(candidate_body) is not None:
            return candidate_body
    return noarg_body


def parse_simple_token_class(token_source: str, token_class: str) -> tuple[dict[str, Any], str | None]:
    if not token_source:
        return {}, "token_source_missing"
    if "TokenImpl" not in token_source:
        return {}, "token_source_not_token_impl"
    constructor_source = token_constructor_body_with_literal_super(token_source, token_class)
    if constructor_source is None:
        return {}, "token_noarg_constructor_missing"
    token_descriptor = token_super_name_and_description(constructor_source)
    if token_descriptor is None:
        return {}, "token_literal_description_missing"
    token_name, description = token_descriptor
    lower_description = description.lower()
    if "creature token" not in lower_description:
        return {}, "token_description_not_creature_token"
    has_colorless_sacrifice_mana = bool(
        "SimpleManaAbility" in constructor_source
        and "SacrificeSourceCost" in constructor_source
        and re.search(r"Mana\.ColorlessMana\s*\(\s*1\s*\)", constructor_source)
        and re.search(
            r"sacrifice this (?:creature|token): add \{c\}",
            lower_description,
        )
    )
    keyword_description = lower_description
    if has_colorless_sacrifice_mana:
        keyword_description = re.sub(
            r'\s+with\s+"sacrifice this (?:creature|token): add \{c\}\.?"\.?',
            "",
            keyword_description,
        )
        keyword_description = re.sub(
            r'\.?\s+it has\s+"sacrifice this (?:creature|token): add \{c\}\.?"\.?',
            "",
            keyword_description,
        )
    unsupported_markers = [
        marker
        for marker in sorted(UNSUPPORTED_TOKEN_DESCRIPTION_MARKERS)
        if marker in keyword_description
    ]
    if unsupported_markers:
        return {}, "token_description_keyword_not_supported"
    description_keywords: list[str] = []
    with_match = re.search(r"\bwith (?P<keywords>.+)$", keyword_description)
    if with_match:
        raw_keywords = re.sub(r"\s+named\s+.+$", "", with_match.group("keywords")).strip()
        keyword_parts = [
            part.strip().rstrip(".")
            for part in re.split(r",| and ", raw_keywords)
            if part.strip()
        ]
        for keyword_part in keyword_parts:
            normalized_keyword = TOKEN_DESCRIPTION_KEYWORDS.get(keyword_part)
            if normalized_keyword is None:
                return {}, "token_description_keyword_not_supported"
            description_keywords.append(normalized_keyword)
    power_match = re.search(r"power\s*=\s*new\s+MageInt\s*\(\s*(\d+)\s*\)", constructor_source)
    toughness_match = re.search(r"toughness\s*=\s*new\s+MageInt\s*\(\s*(\d+)\s*\)", constructor_source)
    if not power_match or not toughness_match:
        return {}, "token_power_toughness_not_fixed"
    if re.search(r"cardType\.add\s*\(\s*CardType\.LAND\s*\)", constructor_source):
        return {}, "token_land_token_runtime_not_supported"
    ability_classes = set(re.findall(r"addAbility\s*\(\s*([A-Za-z]+Ability)", constructor_source))
    ability_classes.update(
        re.findall(r"addAbility\s*\(\s*new\s+([A-Za-z]+Ability)", constructor_source)
    )
    allowed_ability_classes = set(ALLOWED_TOKEN_ABILITY_KEYWORDS)
    if has_colorless_sacrifice_mana:
        allowed_ability_classes.add("SimpleManaAbility")
    unsupported_abilities = ability_classes - allowed_ability_classes
    if unsupported_abilities:
        return {}, "token_ability_not_supported"
    colors = [
        symbol
        for color_name, symbol in TOKEN_COLOR_SETTERS.items()
        if re.search(rf"color\.set{color_name}\s*\(\s*true\s*\)", constructor_source)
    ]
    object_color_matches = re.findall(r"color\.setColor\s*\(\s*ObjectColor\.([A-Z]+)\s*\)", constructor_source)
    object_color_symbols = {
        "WHITE": "W",
        "BLUE": "U",
        "BLACK": "B",
        "RED": "R",
        "GREEN": "G",
    }
    for match in object_color_matches:
        symbol = object_color_symbols.get(match)
        if symbol and symbol not in colors:
            colors.append(symbol)
    if not colors:
        colors = token_colors_from_description(description)
    subtypes = [title_subtype(value) for value in re.findall(r"subtype\.add\s*\(\s*SubType\.([A-Z0-9_]+)\s*\)", constructor_source)]
    token_keywords = [
        keyword
        for ability_class, keyword in ALLOWED_TOKEN_ABILITY_KEYWORDS.items()
        if ability_class in ability_classes
    ]
    for keyword in description_keywords:
        if keyword not in token_keywords:
            token_keywords.append(keyword)
    artifact = bool(
        "artifact creature token" in lower_description
        or re.search(r"cardType\.add\s*\(\s*CardType\.ARTIFACT\s*\)", constructor_source)
    )
    token_data: dict[str, Any] = {
        "xmage_token_class": token_class,
        "token_name": token_name,
        "token_power": int(power_match.group(1)),
        "token_toughness": int(toughness_match.group(1)),
        "token_description": description,
    }
    if subtypes:
        token_data["token_subtype"] = " ".join(subtypes)
    if colors:
        token_data["token_colors"] = colors
    if token_keywords:
        token_data["token_keywords"] = token_keywords
    if "flying" in token_keywords:
        token_data["token_flying"] = True
    if "haste" in token_keywords:
        token_data["token_haste"] = True
    landwalk_types = [
        land_type
        for keyword, land_type in TOKEN_BASIC_LANDWALK_KEYWORDS.items()
        if keyword in token_keywords
    ]
    if landwalk_types:
        token_data["token_landwalk"] = True
        token_data["token_landwalk_land_types"] = landwalk_types
        if len(landwalk_types) == 1:
            token_data["token_landwalk_land_type"] = landwalk_types[0]
    if has_colorless_sacrifice_mana:
        token_data["token_sacrifice_for_colorless_mana"] = True
        token_data["token_mana_activation_requires_sacrifice"] = True
        token_data["token_mana_activation_requires_tap"] = False
        token_data["token_mana_produced"] = 1
        token_data["token_produces"] = "C"
        token_data["token_produced_mana_symbols"] = ["C"]
    if artifact:
        token_data["artifact_tokens"] = True
    return token_data, None


def normalized_token_oracle_phrase(value: str) -> str:
    text = re.sub(r"\([^)]*\)", "", str(value or "").lower())
    text = re.sub(r"\s+", " ", text).strip()
    return text.rstrip(".")


def plural_token_description(description: str) -> str:
    phrase = normalized_token_oracle_phrase(description)
    if " token with " in phrase:
        return phrase.replace(" token with ", " tokens with ", 1)
    if " token named " in phrase:
        return phrase.replace(" token named ", " tokens named ", 1)
    if phrase.endswith(" token"):
        return phrase[:-6] + " tokens"
    return phrase + "s"


def token_oracle_description_variants(token_data: dict[str, Any]) -> set[str]:
    description = normalized_token_oracle_phrase(token_data.get("token_description"))
    variants = {description}
    if token_data.get("token_tapped") and not description.startswith("tapped "):
        variants.add(f"tapped {description}")
    if token_data.get("token_sacrifice_for_colorless_mana"):
        mana_phrases = {
            'with "sacrifice this creature: add {c}."',
            'with "sacrifice this token: add {c}."',
        }
        for phrase in list(variants):
            for source_phrase in mana_phrases:
                if phrase.endswith(source_phrase):
                    base = phrase[: -len(source_phrase)].rstrip()
                    for oracle_phrase in mana_phrases:
                        variants.add(f"{base} {oracle_phrase}".strip())
                    variants.add(f'{base}. it has "sacrifice this token: add {{c}}."'.strip())
                    variants.add(f'{base}. it has "sacrifice this creature: add {{c}}."'.strip())
    return variants


def count_word_for_oracle(count: int) -> str:
    for word, value in NUMBER_WORDS.items():
        if value == count:
            return word
    return str(count)


def dies_create_token_oracle_blocker(
    metadata: dict[str, Any],
    token_data: dict[str, Any],
    token_count: int,
) -> str | None:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    match = re.match(
        r"^(?:when|whenever) (?:this creature|[^,.]+) dies, create (?P<phrase>.+)$",
        text,
    )
    if not match:
        return "dies_token_oracle_not_simple"
    phrase = match.group("phrase").strip()
    if any(marker in text for marker in (" if ", " for each ", " unless ", " instead ")):
        return "dies_token_oracle_not_simple"
    token_descriptions = token_oracle_description_variants(token_data)
    if token_count == 1:
        expected = set()
        for token_description in token_descriptions:
            expected.update(
                {
                    f"a {token_description}",
                    f"an {token_description}",
                    f"one {token_description}",
                }
            )
    else:
        expected = set()
        for token_description in token_descriptions:
            plural_description = plural_token_description(token_description)
            expected.update(
                {
                    f"{token_count} {plural_description}",
                    f"{count_word_for_oracle(token_count)} {plural_description}",
                }
            )
    if phrase not in expected:
        return "dies_token_oracle_not_simple"
    return None


def activated_create_token_from_source(source: str) -> dict[str, Any] | str:
    text = source or ""
    effect_match = re.search(r"new\s+CreateTokenEffect\s*\(", text)
    if effect_match is None:
        return "activated_token_source_no_create_token_effect"
    ability_index = text.rfind("new SimpleActivatedAbility", 0, effect_match.start())
    if ability_index < 0:
        return "activated_token_source_not_simple_activated"
    window = text[ability_index : effect_match.start() + 1800]
    graveyard_self_exile = (
        re.search(r"new\s+SimpleActivatedAbility\s*\(\s*Zone\.GRAVEYARD", window, re.S) is not None
        and "ExileSourceFromGraveCost" in window
    )
    risky_cost_classes = {
        "CompositeCost",
        "ExileFrom",
        "ExileFromGraveCost",
        "ExileFromTopOfLibraryCost",
        "MillCardsCost",
        "OrCost",
        "PayLifeCost",
        "RemoveCounterCost",
        "ReturnToHandSourceCost",
        "ReturnToHandTargetCost",
        "RevealTargetFromHandCost",
        "SacrificeTargetCost",
        "TapTargetCost",
        "UntapSourceCost",
    }
    if not graveyard_self_exile:
        risky_cost_classes.add("ExileSourceFromGraveCost")
    present_risky = sorted(cost for cost in risky_cost_classes if cost in window)
    if present_risky:
        return "activated_token_source_cost_not_supported"
    if graveyard_self_exile and ("TapSourceCost" in window or "SacrificeSourceCost" in window):
        return "activated_token_source_cost_not_supported"
    discard_cost = activation_discard_cost_from_source(window)
    if isinstance(discard_cost, str):
        return discard_cost.replace("activated_damage", "activated_token")
    mana_matches = re.findall(r'ManaCostsImpl<[^>]*>\s*\(\s*"([^"]+)"\s*\)', window, re.S)
    generic_matches = re.findall(r"GenericManaCost\s*\(\s*(\d+)\s*\)", window, re.S)
    colored_matches = re.findall(r"ColoredManaCost\s*\(\s*ColoredManaSymbol\.([WUBRG])\s*\)", window, re.S)
    cost_kinds = sum(1 for matches in (mana_matches, generic_matches, colored_matches) if matches)
    if cost_kinds > 1 or len(mana_matches) > 1 or len(generic_matches) > 1 or len(colored_matches) > 1:
        return "activated_token_source_cost_not_supported"
    if mana_matches:
        cost_text = mana_matches[0]
    elif generic_matches:
        cost_text = "{" + generic_matches[0] + "}"
    elif colored_matches:
        cost_text = "{" + colored_matches[0] + "}"
    else:
        cost_text = "{0}"
    cost_text = canonical_mana_cost_text(cost_text)
    parsed_cost = parse_mana_cost_text(cost_text)
    if parsed_cost is None:
        return "activated_token_source_mana_cost_not_supported"
    activation_cost_generic, activation_cost_colors = parsed_cost
    activation = {
        "activation_cost_mana": cost_text,
        "activation_cost_generic": activation_cost_generic,
        "activation_cost_colors": activation_cost_colors,
        "activation_requires_tap": "TapSourceCost" in window,
        "activation_requires_sacrifice": "SacrificeSourceCost" in window,
        **(discard_cost or {}),
    }
    if graveyard_self_exile:
        activation.update(
            {
                "activation_zone": "graveyard",
                "activation_requires_exile_source_from_graveyard": True,
            }
        )
    return activation


def activated_token_activation_cost_from_oracle_prefix(
    cost_text: str,
    *,
    source_name: str | None = None,
) -> dict[str, Any] | str:
    text = re.sub(r"\s+", " ", str(cost_text or "").strip().lower())
    discard_cost = activation_discard_cost_from_oracle(text)
    if discard_cost:
        discard_pattern = (
            r"(?:^|,\s*)discard "
            r"(?:a card at random|a land card|a card)"
            r"(?:\s*,?|$)"
        )
        text = re.sub(discard_pattern, ",", text).strip(" ,")
    graveyard_self_exile = False
    if "exile " in text and " from your graveyard" in text:
        source_pattern = re.escape(normalize_name(source_name or ""))
        source_phrase = rf"(?:this card|{source_pattern})" if source_pattern else r"this card"
        exile_pattern = rf"(?:^|,\s*)exile {source_phrase} from your graveyard(?:\s*,?|$)"
        if re.search(exile_pattern, text):
            text = re.sub(exile_pattern, ",", text).strip(" ,")
            graveyard_self_exile = True
    activation = activation_cost_from_oracle_prefix(text, allow_source_sacrifice=True)
    if isinstance(activation, str):
        return activation.replace("activated_self_boost", "activated_token")
    if graveyard_self_exile:
        activation.update(
            {
                "activation_zone": "graveyard",
                "activation_requires_exile_source_from_graveyard": True,
            }
        )
    return {**activation, **(discard_cost or {})}


def activated_create_token_oracle_blocker(
    metadata: dict[str, Any],
    token_data: dict[str, Any],
    token_count: int,
    source_activation: dict[str, Any],
) -> str | None:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    if text.count(":") != 1:
        return "activated_token_oracle_not_simple"
    cost_text, effect_text = [part.strip() for part in text.split(":", 1)]
    activation = activated_token_activation_cost_from_oracle_prefix(
        cost_text,
        source_name=str(metadata.get("name") or ""),
    )
    if isinstance(activation, str):
        return activation
    for key in (
        "activation_cost_mana",
        "activation_cost_generic",
        "activation_cost_colors",
        "activation_requires_tap",
        "activation_requires_sacrifice",
        "activation_discard_count",
        "activation_discard_target",
        "activation_requires_discard_card",
        "activation_discard_random",
        "activation_zone",
        "activation_requires_exile_source_from_graveyard",
    ):
        if activation.get(key) != source_activation.get(key):
            return "activated_token_source_oracle_cost_mismatch"
    if any(marker in effect_text for marker in (" for each ", " where x ", " equal to ", " then ")):
        return "activated_token_oracle_not_simple"
    if not effect_text.startswith("create "):
        return "activated_token_oracle_not_simple"
    phrase = effect_text.removeprefix("create ").strip().rstrip(".")
    token_descriptions = token_oracle_description_variants(token_data)
    if token_count == 1:
        expected = set()
        for token_description in token_descriptions:
            expected.update(
                {
                    f"a {token_description}",
                    f"an {token_description}",
                    f"one {token_description}",
                }
            )
    else:
        expected = set()
        for token_description in token_descriptions:
            plural_description = plural_token_description(token_description)
            expected.update(
                {
                    f"{token_count} {plural_description}",
                    f"{count_word_for_oracle(token_count)} {plural_description}",
                }
            )
    if phrase not in expected:
        return "activated_token_oracle_not_simple"
    return None


def controller_target_create_token_effect_from_source(source: str) -> tuple[str, int] | str:
    text = source or ""
    if len(re.findall(r"new\s+CreateTokenControllerTargetEffect\s*\(", text)) != 1:
        return "compensation_token_source_not_single_controller_target_effect"
    match = re.search(
        r"new\s+CreateTokenControllerTargetEffect\s*\(\s*new\s+(\w+)\s*\([^)]*\)\s*"
        r"(?:,\s*(\d+)\s*,\s*(true|false)\s*)?\)",
        text,
        re.S,
    )
    if not match:
        return "compensation_token_source_create_token_not_fixed"
    token_class = match.group(1)
    count = int(match.group(2) or "1")
    if count <= 0:
        return "compensation_token_source_count_not_positive"
    if (match.group(3) or "false") == "true":
        return "compensation_token_source_tapped_not_supported"
    return token_class, count


def removal_compensation_token_oracle_blocker(
    metadata: dict[str, Any],
    *,
    action: str,
    token_data: dict[str, Any],
    token_count: int,
) -> str | None:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    match = re.match(
        rf"^{re.escape(action)} target .+?(?:\. it can't be regenerated)?\. "
        r"its controller (?:creates|puts(?: onto the battlefield)?) (?P<phrase>.+)$",
        text,
    )
    if not match:
        return f"{action}_compensation_token_oracle_not_simple"
    phrase = match.group("phrase").strip()
    if any(marker in phrase for marker in (" if ", " for each ", " unless ", " instead ")):
        return f"{action}_compensation_token_oracle_not_simple"
    if phrase.startswith("a tapped ") or phrase.startswith("an tapped ") or phrase.startswith("tapped "):
        return "compensation_token_oracle_tapped_not_supported"
    token_description = normalized_token_oracle_phrase(token_data.get("token_description"))
    if token_count == 1:
        expected = {
            f"a {token_description}",
            f"an {token_description}",
            f"one {token_description}",
        }
    else:
        plural_description = plural_token_description(token_description)
        expected = {
            f"{token_count} {plural_description}",
            f"{count_word_for_oracle(token_count)} {plural_description}",
        }
    if phrase not in expected:
        return f"{action}_compensation_token_oracle_not_simple"
    return None


def compensation_token_fields(token_data: dict[str, Any], token_count: int) -> dict[str, Any]:
    fields: dict[str, Any] = {
        "target_controller_creature_tokens": token_count,
        "compensation_creature_tokens": token_count,
        "target_controller_token_name": token_data["token_name"],
        "compensation_token_name": token_data["token_name"],
        "target_controller_token_power": token_data["token_power"],
        "compensation_token_power": token_data["token_power"],
        "target_controller_token_toughness": token_data["token_toughness"],
        "compensation_token_toughness": token_data["token_toughness"],
        "compensation_token_status": "dynamic_creature_token_executor",
    }
    optional_pairs = {
        "token_subtype": ("target_controller_token_subtype", "compensation_token_subtype"),
        "token_colors": ("target_controller_token_colors", "compensation_token_colors"),
        "token_keywords": ("target_controller_token_keywords", "compensation_token_keywords"),
        "token_flying": ("target_controller_token_flying", "compensation_token_flying"),
        "token_haste": ("target_controller_token_haste", "compensation_token_haste"),
        "token_landwalk": ("target_controller_token_landwalk", "compensation_token_landwalk"),
        "token_landwalk_land_type": (
            "target_controller_token_landwalk_land_type",
            "compensation_token_landwalk_land_type",
        ),
        "token_landwalk_land_types": (
            "target_controller_token_landwalk_land_types",
            "compensation_token_landwalk_land_types",
        ),
        "artifact_tokens": ("target_controller_artifact_tokens", "compensation_artifact_tokens"),
    }
    for source_key, target_keys in optional_pairs.items():
        if source_key not in token_data:
            continue
        for target_key in target_keys:
            fields[target_key] = token_data[source_key]
    return fields


def is_spell(metadata: dict[str, Any]) -> bool:
    type_line = str(metadata.get("type_line") or "").lower()
    return "instant" in type_line or "sorcery" in type_line


def is_permanent_metadata(metadata: dict[str, Any]) -> bool:
    type_line = str(metadata.get("type_line") or "").lower()
    return any(
        card_type in type_line
        for card_type in ("artifact", "creature", "enchantment", "planeswalker", "battle", "land")
    )


def spell_flags(metadata: dict[str, Any]) -> dict[str, bool]:
    type_line = str(metadata.get("type_line") or "").lower()
    return {
        "instant": "instant" in type_line,
        "sorcery": "sorcery" in type_line,
    }


def effect_classes(row: dict[str, Any]) -> set[str]:
    return {str(value) for value in (row.get("xmage_effect_classes") or []) if str(value)}


def ability_kind(row: dict[str, Any]) -> str:
    return str((row.get("effect_json") or {}).get("ability_kind") or "")


def ability_classes(row: dict[str, Any]) -> set[str]:
    return {str(value) for value in (row.get("xmage_ability_classes") or []) if str(value)}


def oracle_text(metadata: dict[str, Any]) -> str:
    return re.sub(r"\s+", " ", str(metadata.get("oracle_text") or "").strip()).lower()


def oracle_is_play_lands_from_graveyard(metadata: dict[str, Any]) -> bool:
    return oracle_text(metadata) == "you may play lands from your graveyard."


def source_supports_play_lands_from_graveyard(source_text: str) -> bool:
    return (
        "SimpleStaticAbility" in (source_text or "")
        and "PlayFromGraveyardControllerEffect.playLands()" in (source_text or "")
    )


def has_oracle_complexity(metadata: dict[str, Any], tokens: set[str] = SPELL_COMPLEXITY_TOKENS) -> bool:
    text = oracle_text(metadata)
    for token in tokens:
        if re.fullmatch(r"[a-z]+", token):
            if re.search(rf"\b{re.escape(token)}\b(?!['’]s\b)", text):
                return True
            continue
        if token in text:
            return True
    return False


def destroy_target_from_oracle(metadata: dict[str, Any]) -> tuple[str, str] | None:
    text = oracle_text(metadata)
    if "destroy target" not in text:
        return None
    restricted = restricted_battlefield_target_from_oracle(metadata, "destroy")
    if restricted is not None:
        return ("remove_creature" if restricted_target_base(restricted) == "creature" else "remove_permanent"), restricted
    if re.search(r"destroy target artifact or enchantment\b", text):
        return "remove_permanent", "artifact_or_enchantment"
    if re.search(r"destroy target artifact\b", text):
        return "remove_permanent", "artifact"
    if re.search(r"destroy target enchantment\b", text):
        return "remove_permanent", "enchantment"
    if re.search(r"destroy target nonland permanent\b", text):
        return "remove_permanent", "nonland_permanent"
    if re.search(r"destroy target creature, enchantment, or planeswalker\b", text):
        return "remove_permanent", "creature_enchantment_or_planeswalker"
    if re.search(r"destroy target creature or planeswalker\b", text):
        return "remove_permanent", "creature_or_planeswalker"
    if re.search(r"destroy target creature\b", text):
        return "remove_creature", "creature"
    if re.search(r"destroy target land\b", text):
        return "remove_permanent", "land"
    if re.search(r"destroy target permanent\b", text):
        return "remove_permanent", "permanent"
    return None


def fixed_treasure_count_word(value: str) -> int | None:
    word = str(value or "").strip().lower()
    if word in {"a", "an"}:
        return 1
    if word in NUMBER_WORDS:
        return int(NUMBER_WORDS[word])
    if word.isdigit():
        return int(word)
    return None


def destroy_target_create_treasure_from_oracle(
    metadata: dict[str, Any],
) -> tuple[str, str, int] | str | None:
    text = normalized_token_oracle_phrase(oracle_text(metadata))
    match = re.fullmatch(
        r"destroy target (?P<target>.+?)\. create (?P<count>a|an|one|two|three|four|five|\d+) "
        r"treasure tokens?",
        text,
    )
    if not match:
        return "destroy_treasure_oracle_not_exact"
    count = fixed_treasure_count_word(match.group("count"))
    if count is None or count <= 0:
        return "destroy_treasure_oracle_count_not_fixed_positive"
    target_phrase = match.group("target").strip()
    target_map = {
        "creature": ("remove_creature", "creature"),
        "artifact or enchantment": ("remove_permanent", "artifact_or_enchantment"),
        "creature or planeswalker": ("remove_permanent", "creature_or_planeswalker"),
        "nonland permanent": ("remove_permanent", "nonland_permanent"),
        "permanent": ("remove_permanent", "permanent"),
        "artifact": ("remove_permanent", "artifact"),
        "enchantment": ("remove_permanent", "enchantment"),
        "land": ("remove_permanent", "land"),
    }
    mapped = target_map.get(target_phrase)
    if mapped is None:
        return "destroy_treasure_oracle_target_not_supported"
    effect, target_type = mapped
    return effect, target_type, count


def destroy_target_create_treasure_from_source(source: str) -> int | str:
    text = source or ""
    if has_additional_cost(text):
        return "destroy_treasure_additional_cost_not_supported"
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return "destroy_treasure_target_pointer_not_supported"
    if len(re.findall(r"new\s+DestroyTargetEffect\s*\(\s*\)", text, re.S)) != 1:
        return "destroy_treasure_source_destroy_not_single"
    parsed_token = fixed_create_token_effect_from_source(text)
    if isinstance(parsed_token, dict):
        return "destroy_treasure_source_token_count_dynamic"
    if isinstance(parsed_token, str):
        return parsed_token
    token_class, token_count = parsed_token
    if token_class != "TreasureToken":
        return "destroy_treasure_source_token_not_treasure"
    return int(token_count)


def creature_etb_create_treasure_from_oracle(metadata: dict[str, Any]) -> int | dict[str, Any] | str:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    match = re.fullmatch(
        r"when (?:this creature|[a-z0-9 ,'-]+) enters(?: the battlefield)?, create "
        r"(?P<count>a|an|one|two|three|four|five|\d+) treasure tokens?",
        text,
    )
    if not match:
        return "etb_treasure_oracle_not_exact"
    count = fixed_treasure_count_word(match.group("count"))
    if count is None or count <= 0:
        return "etb_treasure_oracle_count_not_fixed_positive"
    return int(count)


def conditional_creature_etb_create_treasure_from_oracle(metadata: dict[str, Any]) -> dict[str, Any] | str:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    match = re.fullmatch(
        r"when (?:this creature|[a-z0-9 ,'-]+) enters(?: the battlefield)?, "
        r"if an opponent controls more lands than you, you create "
        r"(?P<count>a|an|one|two|three|four|five|\d+) treasure tokens?",
        text,
    )
    if not match:
        return "etb_treasure_oracle_not_exact"
    count = fixed_treasure_count_word(match.group("count"))
    if count is None or count <= 0:
        return "etb_treasure_oracle_count_not_fixed_positive"
    return {
        "count": int(count),
        "condition": "opponent_controls_more_lands",
    }


def creature_etb_treasure_count_and_condition_from_oracle(
    metadata: dict[str, Any],
) -> tuple[int, str | None] | str:
    parsed = creature_etb_create_treasure_from_oracle(metadata)
    if parsed == "etb_treasure_oracle_not_exact":
        parsed = conditional_creature_etb_create_treasure_from_oracle(metadata)
    if isinstance(parsed, str):
        return parsed
    if isinstance(parsed, dict):
        return int(parsed["count"]), str(parsed.get("condition") or "") or None
    return int(parsed), None


def creature_dies_create_treasure_from_oracle(metadata: dict[str, Any]) -> int | str:
    text = normalized_token_oracle_phrase(oracle_text_after_leading_static_keywords(metadata))
    match = re.fullmatch(
        r"(?:when|whenever) (?:this creature|[a-z0-9 ,'-]+) dies, create "
        r"(?P<count>a|an|one|two|three|four|five|\d+) treasure tokens?",
        text,
    )
    if not match:
        return "dies_treasure_oracle_not_exact"
    if any(marker in text for marker in (" if ", " for each ", " unless ", " instead ")):
        return "dies_treasure_oracle_not_simple"
    count = fixed_treasure_count_word(match.group("count"))
    if count is None or count <= 0:
        return "dies_treasure_oracle_count_not_fixed_positive"
    return int(count)


def simple_destroy_gain_life_from_source(source: str) -> tuple[str, int] | None:
    text = source or ""
    if has_additional_cost(text):
        return None
    if "TargetPointer" in text or ".setTargetPointer" in text:
        return None
    if len(re.findall(r"new\s+DestroyTargetEffect\s*\(\s*\)", text, re.S)) != 1:
        return None
    life_matches = re.findall(r"new\s+GainLifeEffect\s*\(\s*(\d+)\s*\)", text, re.S)
    if len(life_matches) != 1:
        return None
    target_classes = re.findall(r"new\s+(Target\w+)\s*\(", text)
    if len(target_classes) != 1:
        return None
    target_patterns = [
        (
            "artifact_or_enchantment",
            r"new\s+TargetPermanent\s*\(\s*StaticFilters\.FILTER_PERMANENT_ARTIFACT_OR_ENCHANTMENT\s*\)",
        ),
        (
            "artifact_or_creature",
            r"new\s+TargetPermanent\s*\(\s*StaticFilters\.FILTER_PERMANENT_ARTIFACT_OR_CREATURE\s*\)",
        ),
        ("artifact", r"new\s+TargetArtifactPermanent\s*\(\s*\)"),
        ("enchantment", r"new\s+TargetEnchantmentPermanent\s*\(\s*\)"),
        ("creature", r"new\s+TargetCreaturePermanent\s*\(\s*\)"),
        ("land", r"new\s+TargetLandPermanent\s*\(\s*\)"),
    ]
    matched_targets = [
        target
        for target, pattern in target_patterns
        if re.search(pattern, text, re.S)
    ]
    if len(matched_targets) != 1:
        return None
    return matched_targets[0], int(life_matches[0])


def simple_destroy_gain_life_from_oracle(metadata: dict[str, Any]) -> tuple[str, int] | None:
    text = oracle_text(metadata)
    target_patterns = [
        ("artifact_or_enchantment", r"artifact or enchantment"),
        ("artifact_or_creature", r"artifact or creature"),
        ("artifact", r"artifact"),
        ("enchantment", r"enchantment"),
        ("creature", r"creature"),
        ("land", r"land"),
    ]
    for target, target_phrase in target_patterns:
        match = re.match(
            rf"^destroy target {target_phrase}\. you gain (\d+) life\.?$",
            text,
        )
        if match:
            return target, int(match.group(1))
    return None


