def is_creature_etb_add_counters_unit(row: dict[str, Any]) -> bool:
    if str(row.get("adapter_work_unit") or "") != ADD_COUNTERS_TARGET_UNIT:
        return False
    abilities = ability_classes(row)
    remaining = abilities - {"EntersBattlefieldTriggeredAbility"}
    return (
        effect_classes(row) == {"AddCountersTargetEffect"}
        and "EntersBattlefieldTriggeredAbility" in abilities
        and remaining.issubset(STATIC_SELF_KEYWORD_ABILITY_CLASSES)
        and set(row.get("xmage_signals") or []) == {"targeting", "counter", "triggered_ability"}
    )


def is_permanent_activated_self_add_counters_unit(row: dict[str, Any]) -> bool:
    if str(row.get("adapter_work_unit") or "") != ADD_COUNTERS_SOURCE_UNIT:
        return False
    abilities = ability_classes(row)
    remaining = abilities - {"SimpleActivatedAbility"}
    return (
        effect_classes(row) == {"AddCountersSourceEffect"}
        and "SimpleActivatedAbility" in abilities
        and remaining.issubset(STATIC_SELF_KEYWORD_ABILITY_CLASSES)
        and set(row.get("xmage_signals") or []) == {"counter", "activated_ability"}
    )


def is_creature_tap_damage_unit(row: dict[str, Any]) -> bool:
    if str(row.get("adapter_work_unit") or "") != DAMAGE_UNIT:
        return False
    return (
        effect_classes(row) == {"DamageTargetEffect"}
        and ability_classes(row) == {"SimpleActivatedAbility"}
        and set(row.get("xmage_signals") or []) == {"targeting", "activated_ability"}
    )


def is_boost_keyword_spell_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    return (
        str(row.get("adapter_work_unit") or "") == BOOST_KEYWORD_UNIT
        and effect_classes(row) == {"BoostTargetEffect", "GainAbilityTargetEffect"}
        and set(row.get("xmage_signals") or []) == {"targeting"}
        and len(abilities) == 1
        and next(iter(abilities)) in TARGET_GRANT_KEYWORD_ABILITY_CLASSES
    )


def is_target_keyword_spell_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    return (
        str(row.get("adapter_work_unit") or "") == BOOST_KEYWORD_UNIT
        and effect_classes(row) == {"GainAbilityTargetEffect"}
        and set(row.get("xmage_signals") or []) == {"targeting"}
        and bool(abilities)
        and abilities.issubset(TARGET_GRANT_KEYWORD_ABILITY_CLASSES)
    )


def is_permanent_activated_target_keyword_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    keyword_abilities = abilities.intersection(TARGET_GRANT_KEYWORD_ABILITY_CLASSES)
    return (
        str(row.get("adapter_work_unit") or "") == BOOST_KEYWORD_UNIT
        and effect_classes(row) == {"GainAbilityTargetEffect"}
        and set(row.get("xmage_signals") or []) == {"targeting", "activated_ability"}
        and "SimpleActivatedAbility" in abilities
        and len(keyword_abilities) == 1
        and len(abilities - {"SimpleActivatedAbility"} - keyword_abilities) == 0
    )


def is_permanent_activated_self_keyword_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    keyword_abilities = abilities.intersection(TARGET_GRANT_KEYWORD_ABILITY_CLASSES)
    return (
        str(row.get("adapter_work_unit") or "").startswith(SELF_KEYWORD_ACTIVATED_UNIT_PREFIX)
        and effect_classes(row) == {"GainAbilitySourceEffect"}
        and set(row.get("xmage_signals") or []) == {"activated_ability"}
        and "SimpleActivatedAbility" in abilities
        and len(keyword_abilities) == 1
        and len(abilities - {"SimpleActivatedAbility"} - keyword_abilities) == 0
    )


def is_permanent_activated_regenerate_source_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    remaining = abilities - {"SimpleActivatedAbility"}
    return (
        str(row.get("adapter_work_unit") or "").startswith(
            "xmage_signature::RegenerateSourceEffect::"
        )
        and effect_classes(row) == {"RegenerateSourceEffect"}
        and "SimpleActivatedAbility" in abilities
        and remaining.issubset(STATIC_SELF_KEYWORD_ABILITY_CLASSES)
        and set(row.get("xmage_signals") or []) == {"activated_ability"}
    )


def is_creature_attack_target_keyword_unit(row: dict[str, Any]) -> bool:
    abilities = ability_classes(row)
    keyword_abilities = abilities.intersection(TARGET_GRANT_KEYWORD_ABILITY_CLASSES)
    remaining = abilities - {"AttacksTriggeredAbility"} - keyword_abilities
    return (
        str(row.get("adapter_work_unit") or "") == BOOST_KEYWORD_UNIT
        and effect_classes(row) == {"GainAbilityTargetEffect"}
        and set(row.get("xmage_signals") or []) == {"targeting", "triggered_ability"}
        and "AttacksTriggeredAbility" in abilities
        and len(keyword_abilities) == 1
        and remaining.issubset(STATIC_SELF_KEYWORD_ABILITY_CLASSES)
    )


def keywords_from_ability_classes(row: dict[str, Any]) -> set[str]:
    return {
        STATIC_SELF_KEYWORD_ABILITY_CLASSES[ability]
        for ability in ability_classes(row)
        if ability in STATIC_SELF_KEYWORD_ABILITY_CLASSES
    }


def keywords_from_source_added_ability_classes(source_text: str, row: dict[str, Any]) -> set[str]:
    text = str(source_text or "")
    keywords: set[str] = set()
    for ability in ability_classes(row):
        keyword = STATIC_SELF_KEYWORD_ABILITY_CLASSES.get(ability)
        if not keyword:
            continue
        pattern = (
            r"addAbility\s*\([^;]*\b"
            + re.escape(ability)
            + r"\s*(?:\.getInstance\s*\(\)|\()"
        )
        if re.search(pattern, text, re.S):
            keywords.add(keyword)
    return keywords


def normalize_keyword_phrase(value: str) -> str:
    return re.sub(r"\s+", "_", str(value or "").strip().lower())


def ordered_keywords(keywords: set[str]) -> list[str]:
    return [keyword for keyword in STATIC_SELF_KEYWORD_ORDER if keyword in keywords]


def ordered_protection_colors(colors: set[str] | list[str]) -> list[str]:
    present = {str(color or "").strip().lower() for color in colors if str(color or "").strip()}
    return [color for color in PROTECTION_COLOR_ORDER if color in present]


def ordered_protection_card_types(card_types: set[str] | list[str]) -> list[str]:
    present = {
        str(card_type or "").strip().lower()
        for card_type in card_types
        if str(card_type or "").strip()
    }
    return [card_type for card_type in PROTECTION_CARD_TYPE_ORDER if card_type in present]


def ordered_protection_subtypes(subtypes: set[str] | list[str]) -> list[str]:
    present = {
        str(subtype or "").strip().lower()
        for subtype in subtypes
        if str(subtype or "").strip()
    }
    return sorted(present)


def protection_from_colors_from_oracle(metadata: dict[str, Any]) -> list[str] | None:
    raw = str(metadata.get("oracle_text") or "").strip()
    if not raw:
        return None
    text = re.sub(r"\([^)]*\)", "", raw)
    text = re.sub(r"\s+", " ", text.replace("\n", ", ")).strip().rstrip(".").lower()
    text = oracle_protection_clause(text) or text
    match = re.fullmatch(r"protection from (.+)", text)
    if not match:
        return None
    body = re.sub(r"\bfrom\s+", "", match.group(1))
    body = re.sub(r"\s*,\s*and\s+", ", ", body)
    if body in {"all colors", "each color"}:
        return list(PROTECTION_COLOR_ORDER)
    parts = [
        part.strip()
        for part in re.split(r"\s*,\s*|\s+and\s+", body)
        if part.strip()
    ]
    if not parts:
        return None
    if any(part not in PROTECTION_COLOR_WORDS for part in parts):
        return None
    return ordered_protection_colors(parts)


def protection_from_card_types_from_oracle(metadata: dict[str, Any]) -> list[str] | None:
    raw = str(metadata.get("oracle_text") or "").strip()
