def library_tutor_specs_match(source_tutor: dict[str, Any], oracle_tutor: dict[str, Any]) -> str | None:
    scalar_keys = (
        "target",
        "count",
        "up_to_count",
        "destination",
        "enters_tapped",
        "target_mana_value_min",
        "target_mana_value_max",
        "requires_different_names",
    )
    list_keys = (
        "target_subtypes",
        "target_card_types",
        "target_colors",
        "required_supertypes",
        "target_names",
    )
    for key in scalar_keys:
        if source_tutor.get(key) != oracle_tutor.get(key):
            return key
    for key in list_keys:
        source_values = sorted(str(value).lower() for value in source_tutor.get(key) or [])
        oracle_values = sorted(str(value).lower() for value in oracle_tutor.get(key) or [])
        if source_values != oracle_values:
            return key
    return None


def library_tutor_effect_constraints(tutor_spec: dict[str, Any]) -> dict[str, Any]:
    constraints: dict[str, Any] = {}
    for key in (
        "target_subtypes",
        "target_card_types",
        "target_colors",
        "required_supertypes",
        "target_names",
        "target_mana_value_min",
        "target_mana_value_max",
        "requires_different_names",
    ):
        if key in tutor_spec:
            constraints[key] = tutor_spec[key]
    return constraints


def target_constraints_for(target: str) -> dict[str, Any]:
    mana_value_target = mana_value_restricted_target_parts(target)
    if mana_value_target is not None:
        base = str(mana_value_target["base"])
        if base == "nonland_permanent":
            constraints: dict[str, Any] = {
                "card_types": ["permanent"],
                "exclude_card_types": ["land"],
            }
        else:
            constraints = {"card_types": [base]}
        op = str(mana_value_target["op"])
        value = int(mana_value_target["value"])
        if op == "or_less":
            constraints["mana_value_max"] = value
        elif op == "or_greater":
            constraints["mana_value_min"] = value
        else:
            constraints["mana_value_min"] = value
            constraints["mana_value_max"] = value
        return constraints
    if target == "any_target":
        return {"scope": "any_target"}
